---
import Layout from '../../layouts/Layout.astro';
import PageHero from '../../components/PageHero.astro';
import BlogGrid from '../../components/BlogGrid.astro';
import CTA from '../../components/CTA.astro';
import { getPublishedPosts } from '../../lib/blog';
import { blogCategories } from '../../data/blogCategories';

const posts = await getPublishedPosts();
const [featured, ...rest] = posts;
const crumbs = [{ name: 'Home', href: '/' }, { name: 'Blog', href: '/blog' }];
---
<Layout
  title="Solar Energy Blog — Guides, Tips & Insights"
  description="The Apex Solar blog: expert guides on solar costs, tax credits, battery storage, EV charging, financing and maintenance for American homes and businesses."
  keywords={['solar blog', 'solar energy guides', 'solar tips', 'solar news']}
  canonical="/blog"
  breadcrumbs={crumbs}
>
  <PageHero
    eyebrow="Solar Insights"
    title="The Apex Solar blog"
    subtitle="Expert guides to help you make confident, money-saving decisions about solar, storage and EV charging."
    crumbs={crumbs}
  />

  <section class="section">
    <div class="container-xl">
      <!-- Category pills -->
      <div class="mb-12 flex flex-wrap items-center justify-center gap-2">
        <a href="/blog" class="rounded-full bg-solar-500 px-4 py-2 text-sm font-semibold text-white">All</a>
        {blogCategories.map((c) => (
          <a href={`/blog/category/${c.slug}`} class="rounded-full bg-gray-100 px-4 py-2 text-sm font-semibold text-gray-600 hover:bg-gray-200">{c.name}</a>
        ))}
      </div>

      <!-- Featured -->
      {featured && (
        <a href={`/blog/${featured.id}`} class="group card mb-14 grid overflow-hidden lg:grid-cols-2">
          <div class="relative aspect-[16/10] overflow-hidden bg-gray-100 lg:aspect-auto">
            <img src={featured.data.featuredImage} alt={featured.data.featuredImageAlt} width="800" height="500" fetchpriority="high" decoding="async" class="size-full object-cover transition-transform duration-500 group-hover:scale-105" />
          </div>
          <div class="flex flex-col justify-center p-8 lg:p-12">
            <span class="eyebrow w-fit">Featured</span>
            <h2 class="mt-4 font-display text-2xl font-bold text-gray-900 group-hover:text-solar-600 lg:text-3xl">{featured.data.title}</h2>
            <p class="mt-3 text-gray-500">{featured.data.excerpt}</p>
            <span class="mt-6 inline-flex items-center gap-1.5 font-semibold text-solar-600">Read article →</span>
          </div>
        </a>
      )}

      <BlogGrid posts={rest} />
    </div>
  </section>

  <CTA />
</Layout>

