---
import Layout from '../layouts/Layout.astro';
import PageHero from '../components/PageHero.astro';
import FAQAccordion from '../components/FAQAccordion.astro';
import CTA from '../components/CTA.astro';
import { faqs } from '../data/faqs';
import { faqSchema } from '../lib/schema';

const topics = [
  { key: 'general', label: 'General' },
  { key: 'cost', label: 'Cost & Financing' },
  { key: 'install', label: 'Installation' },
  { key: 'storage', label: 'Battery & Storage' },
  { key: 'incentives', label: 'Incentives' },
  { key: 'service', label: 'Service & Maintenance' },
] as const;

const crumbs = [{ name: 'Home', href: '/' }, { name: 'FAQ', href: '/faq' }];
const schemas = [faqSchema(faqs.map((f) => ({ question: f.question, answer: f.answer })))];
---
<Layout
  title="Frequently Asked Questions About Solar"
  description="Answers to the most common questions about solar cost, financing, the federal tax credit, installation, battery storage and maintenance — from the Apex Solar team."
  keywords={['solar faq', 'solar questions', 'solar cost questions', 'solar tax credit faq']}
  canonical="/faq"
  breadcrumbs={crumbs}
  schemas={schemas}
>
  <PageHero eyebrow="FAQ" title="Your solar questions, answered" subtitle="Everything you need to know before going solar. Still curious? Our specialists are just a call away." crumbs={crumbs} />

  <section class="section">
    <div class="container-xl">
      {topics.map((topic) => {
        const list = faqs.filter((f) => f.topic === topic.key);
        if (!list.length) return null;
        return (
          <div class="mb-12">
            <h2 class="mb-4 text-center font-display text-2xl font-bold text-gray-900">{topic.label}</h2>
            <FAQAccordion faqs={list} />
          </div>
        );
      })}
    </div>
  </section>

  <CTA title="Still have questions?" subtitle="Our friendly solar specialists are happy to help — no pressure, no jargon, just straight answers." />
</Layout>

---
import Layout from '../layouts/Layout.astro';
import PageHero from '../components/PageHero.astro';
import { company } from '../data/company';
const crumbs = [{ name: 'Home', href: '/' }, { name: 'Privacy Policy', href: '/privacy-policy' }];
const updated = 'June 1, 2026';
const sections = [
  { h: 'Information We Collect', p: ['We collect information you provide directly — such as your name, email, phone number, address and details about your property — when you request a quote, contact us or subscribe to updates.', 'We also automatically collect limited technical data (IP address, browser type, pages visited) through cookies and analytics to improve our website.'] },
  { h: 'How We Use Your Information', p: ['To prepare and deliver your solar quote and design.', 'To communicate with you about our services, your project and relevant offers.', 'To improve our website, services and customer experience.', 'To comply with legal obligations.'] },
  { h: 'How We Share Information', p: ['We do not sell your personal information. We may share it with trusted service providers (financing partners, scheduling tools, CRM) solely to deliver our services, and as required by law.'] },
  { h: 'Cookies & Analytics', p: ['Our site uses cookies and privacy-respecting analytics to understand usage and improve performance. You can disable cookies in your browser settings.'] },
  { h: 'Your Rights', p: ['Depending on your state, you may have the right to access, correct or delete your personal information, and to opt out of marketing communications. Contact us to exercise these rights.'] },
  { h: 'Data Security', p: ['We use industry-standard safeguards to protect your information. No method of transmission is 100% secure, but we work diligently to keep your data safe.'] },
  { h: 'Contact Us', p: [`Questions about this policy? Email ${company.email} or call ${company.phone}.`] },
];
---
<Layout title="Privacy Policy" description={`Privacy policy for ${company.name}. Learn how we collect, use and protect your personal information.`} canonical="/privacy-policy" robots="index, follow" breadcrumbs={crumbs}>
  <PageHero eyebrow="Legal" title="Privacy Policy" subtitle={`Last updated: ${updated}`} crumbs={crumbs} />
  <section class="section">
    <div class="container-xl">
      <div class="prose-solar mx-auto max-w-3xl">
        <p>{company.legalName} (“we”, “us”) respects your privacy. This policy explains what we collect, how we use it, and your choices.</p>
        {sections.map((s) => (
          <>
            <h2>{s.h}</h2>
            {s.p.map((para) => <p>{para}</p>)}
          </>
        ))}
      </div>
    </div>
  </section>
</Layout>

---
import Layout from '../../layouts/Layout.astro';
import PageHero from '../../components/PageHero.astro';
import CTA from '../../components/CTA.astro';
import Icon from '../../components/Icon.astro';
import { projects, projectTypes } from '../../data/projects';

const crumbs = [{ name: 'Home', href: '/' }, { name: 'Projects', href: '/projects' }];
const typeColor: Record<string, string> = {
  Residential: 'bg-solar-50 text-solar-700 ring-solar-100',
  Commercial: 'bg-energy-50 text-energy-700 ring-energy-100',
  Industrial: 'bg-gray-100 text-gray-700 ring-gray-200',
  Agricultural: 'bg-grid-50 text-grid-700 ring-grid-100',
};
---
<Layout
  title="Solar Projects & Installations Portfolio"
  description="Browse Apex Solar's portfolio of residential, commercial, industrial and agricultural solar installations across the USA — with real system sizes, savings and results."
  keywords={['solar projects', 'solar installations', 'solar portfolio', 'commercial solar projects']}
  canonical="/projects"
  breadcrumbs={crumbs}
>
  <PageHero
    eyebrow="Our Work"
    title="A portfolio of proven solar results"
    subtitle="Real installations, real savings. Explore our projects across homes, businesses, industry and farms nationwide."
    image="/images/projects/projects-hero.jpg"
    imageAlt="Aerial view of a large completed solar installation"
    crumbs={crumbs}
  />

  <section class="section" x-data="{ filter: 'All' }">
    <div class="container-xl">
      <!-- Filter -->
      <div class="mb-12 flex flex-wrap items-center justify-center gap-2">
        {['All', ...projectTypes].map((t) => (
          <button
            type="button"
            @click={`filter = '${t}'`}
            class="rounded-full px-4 py-2 text-sm font-semibold transition-colors"
            :class={`filter === '${t}' ? 'bg-solar-500 text-white shadow-[var(--shadow-glow)]' : 'bg-gray-100 text-gray-600 hover:bg-gray-200'`}
          >{t}</button>
        ))}
      </div>

      <div class="grid grid-cols-1 gap-6 sm:grid-cols-2 lg:grid-cols-3">
        {projects.map((p, i) => (
          <a
            href={`/projects/${p.slug}`}
            class="group card overflow-hidden transition-all duration-300 hover:-translate-y-1 hover:shadow-xl"
            x-show={`filter === 'All' || filter === '${p.type}'`}
            x-transition
          >
            <div class="relative aspect-[4/3] overflow-hidden bg-gray-100">
              <img src={p.image} alt={p.imageAlt} width="600" height="450" loading={i < 6 ? 'eager' : 'lazy'} decoding="async" class="size-full object-cover transition-transform duration-500 group-hover:scale-105" />
              <span class={`absolute left-3 top-3 rounded-full px-2.5 py-1 text-xs font-semibold ring-1 ${typeColor[p.type]}`}>{p.type}</span>
              <span class="absolute bottom-3 right-3 rounded-full bg-white/90 px-2.5 py-1 text-xs font-bold text-energy-700">{p.systemSize}</span>
            </div>
            <div class="p-6">
              <p class="flex items-center gap-1 text-xs font-medium text-gray-400"><Icon name="map-pin" class="size-3.5" /> {p.location}, {p.state}</p>
              <h3 class="mt-1.5 font-display text-lg font-bold text-gray-900 group-hover:text-solar-600">{p.name}</h3>
              <p class="mt-2 line-clamp-2 text-sm text-gray-500">{p.summary}</p>
            </div>
          </a>
        ))}
      </div>
    </div>
  </section>

  <CTA />
</Layout>

---
import Layout from '../../layouts/Layout.astro';
import PageHero from '../../components/PageHero.astro';
import SectionTitle from '../../components/SectionTitle.astro';
import ServicesGrid from '../../components/ServicesGrid.astro';
import CTA from '../../components/CTA.astro';
import Icon from '../../components/Icon.astro';
import { serviceCategories, servicesByCategory, type ServiceCategory } from '../../data/services';

const crumbs = [{ name: 'Home', href: '/' }, { name: 'Services', href: '/services' }];
const order: ServiceCategory[] = ['residential', 'commercial', 'storage', 'specialty', 'support'];
---
<Layout
  title="Solar Services — Residential, Commercial, Storage & EV"
  description="Explore Apex Solar's full range of services: residential & commercial solar, battery storage, EV charging, solar roofing, agricultural solar, repairs, cleaning and monitoring."
  keywords={['solar services', 'solar installation services', 'commercial solar', 'battery storage', 'solar maintenance']}
  canonical="/services"
  breadcrumbs={crumbs}
>
  <PageHero
    eyebrow="Our Services"
    title="Complete solar energy solutions, end to end"
    subtitle="From your first panel to lifetime maintenance — residential, commercial, storage, EV and specialty solar, all under one expert roof."
    image="/images/services/services-hero.jpg"
    imageAlt="Solar technicians reviewing plans on a rooftop installation"
    crumbs={crumbs}
  />

  {order.map((cat, i) => {
    const meta = serviceCategories[cat];
    const list = servicesByCategory(cat);
    return (
      <section class={`section ${i % 2 === 1 ? 'bg-gray-50' : ''}`}>
        <div class="container-xl">
          <div class="flex items-center gap-4">
            <span class="grid size-12 place-items-center rounded-2xl bg-solar-50 text-solar-600 ring-1 ring-solar-100"><Icon name={meta.icon} class="size-6" /></span>
            <div>
              <h2 class="font-display text-2xl font-bold text-gray-900">{meta.label}</h2>
              <p class="text-gray-500">{meta.description}</p>
            </div>
          </div>
          <div class="mt-10">
            <ServicesGrid services={list} columns={3} />
          </div>
        </div>
      </section>
    );
  })}

  <CTA />
</Layout>

---
import Layout from '../layouts/Layout.astro';
import PageHero from '../components/PageHero.astro';
import Icon from '../components/Icon.astro';
import { services } from '../data/services';
import { locations } from '../data/locations';
import { projects } from '../data/projects';
import { blogCategories } from '../data/blogCategories';
import { getPublishedPosts } from '../lib/blog';

const posts = await getPublishedPosts();
const crumbs = [{ name: 'Home', href: '/' }, { name: 'Sitemap', href: '/sitemap' }];

const groups = [
  { title: 'Main Pages', links: [
    { label: 'Home', href: '/' }, { label: 'About Us', href: '/about' }, { label: 'Services', href: '/services' },
    { label: 'Projects', href: '/projects' }, { label: 'Case Studies', href: '/case-studies' }, { label: 'Blog', href: '/blog' },
    { label: 'Locations', href: '/locations' }, { label: 'FAQ', href: '/faq' }, { label: 'Testimonials', href: '/testimonials' },
    { label: 'Careers', href: '/careers' }, { label: 'Contact', href: '/contact' }, { label: 'Get Free Quote', href: '/quote' },
  ] },
  { title: 'Resources', links: [
    { label: 'Financing Options', href: '/financing' }, { label: 'Solar Incentives', href: '/incentives' }, { label: 'Solar Tax Credits', href: '/tax-credits' },
    { label: 'Privacy Policy', href: '/privacy-policy' }, { label: 'Terms & Conditions', href: '/terms' },
  ] },
  { title: 'Services', links: services.map((s) => ({ label: s.menuTitle, href: `/services/${s.slug}` })) },
  { title: 'Locations', links: locations.map((l) => ({ label: l.state, href: `/locations/${l.slug}` })) },
  { title: 'Blog Categories', links: blogCategories.map((c) => ({ label: c.name, href: `/blog/category/${c.slug}` })) },
  { title: 'Blog Articles', links: posts.map((p) => ({ label: p.data.title, href: `/blog/${p.id}` })) },
  { title: 'Projects', links: projects.map((p) => ({ label: p.name, href: `/projects/${p.slug}` })) },
];
---
<Layout title="Sitemap" description="Browse every page on the Apex Solar website — services, projects, locations, blog articles and resources." canonical="/sitemap" breadcrumbs={crumbs}>
  <PageHero eyebrow="Sitemap" title="Find your way around" subtitle="Every page on the Apex Solar site, organized for easy browsing." crumbs={crumbs} />
  <section class="section">
    <div class="container-xl grid gap-10 sm:grid-cols-2 lg:grid-cols-3">
      {groups.map((g) => (
        <div>
          <h2 class="flex items-center gap-2 font-display text-lg font-bold text-gray-900"><Icon name="grid" class="size-5 text-solar-500" /> {g.title}</h2>
          <ul class="mt-4 space-y-2 border-l border-gray-100 pl-4">
            {g.links.map((l) => (
              <li><a href={l.href} class="text-sm text-gray-600 hover:text-solar-600">{l.label}</a></li>
            ))}
          </ul>
        </div>
      ))}
    </div>
  </section>
</Layout>

